class Solution {
    public int strongPasswordChecker(String password) {
        int missingType = 3;
        if (hasLower(password)) missingType--;
        if (hasUpper(password)) missingType--;
        if (hasDigit(password)) missingType--;

        int one = 0, two = 0;
        int i = 2;
        while (i < password.length()) {
            if (password.charAt(i) == password.charAt(i-1) && password.charAt(i) == password.charAt(i-2)) {
                int length = 2;
                while (i < password.length() && password.charAt(i) == password.charAt(i-1)) {
                    i++;
                    length++;
                }
                if (length % 3 == 0) one++;
                else if (length % 3 == 1) two++;
            } else {
                i++;
            }
        }

        if (password.length() < 6) {
            return Math.max(6 - password.length(), missingType);
        } else if (password.length() <= 20) {
            return Math.max(missingType, one);
        } else {
            int delete = password.length() - 20;
            one -= Math.min(delete, one);
            two -= Math.min(Math.max(delete - one, 0), two) / 2;
            two -= Math.max(delete - one - 2 * two, 0) / 3;
            return delete + Math.max(missingType, one + two);
        }
    }

    private boolean hasLower(String password) {
        for (char c : password.toCharArray()) {
            if (Character.isLowerCase(c)) return true;
        }
        return false;
    }

    private boolean hasUpper(String password) {
        for (char c : password.toCharArray()) {
            if (Character.isUpperCase(c)) return true;
        }
        return false;
    }

    private boolean hasDigit(String password) {
        for (char c : password.toCharArray()) {
            if (Character.isDigit(c)) return true;
        }
        return false;
    }
}
